import CryptoJS from 'crypto-js';

export function normalizeEmail(value = '') {
  return value.trim().toLowerCase();
}

export function normalizePhone(value = '') {
  return value.replace(/[^0-9]/g, '');
}

export function sha256(value = '') {
  return CryptoJS.SHA256(value).toString(CryptoJS.enc.Hex);
}

export function hashUser(user) {
  const email = normalizeEmail(user.email || '');
  const phone = normalizePhone(user.phone || '');

  return {
    email: email ? sha256(email) : null,
    phone: phone ? sha256(phone) : null,
    fn: user.firstName ? sha256(user.firstName.trim().toLowerCase()) : null,
    ln: user.lastName ? sha256(user.lastName.trim().toLowerCase()) : null,
    country: user.country ? sha256(user.country.trim().toLowerCase()) : null
  };
}

