const API_VERSION = process.env.META_API_VERSION || 'v23.0';
const GRAPH_BASE = `https://graph.facebook.com/${API_VERSION}`;

function getToken() {
  const token = process.env.META_ACCESS_TOKEN;
  if (!token) throw new Error('META_ACCESS_TOKEN missing');
  return token;
}

export async function metaFetch(path, options = {}) {
  const token = getToken();
  const method = options.method || 'GET';
  const headers = {
    'Content-Type': 'application/json',
    ...(options.headers || {})
  };

  let url = `${GRAPH_BASE}${path}`;
  const body = options.body ? JSON.parse(options.body) : null;

  if (method === 'GET') {
    const query = new URLSearchParams({ access_token: token, ...(options.query || {}) });
    url += `?${query.toString()}`;
  }

  const res = await fetch(url, {
    method,
    headers,
    body: method === 'GET' ? undefined : JSON.stringify({ ...(body || {}), access_token: token })
  });

  const data = await res.json();
  if (!res.ok || data.error) {
    throw new Error(JSON.stringify(data));
  }

  return data;
}

export async function sendConversionsEvent({ eventName, eventId, userData, customData = {}, eventSourceUrl }) {
  return metaFetch(`/${process.env.META_PIXEL_ID}/events`, {
    method: 'POST',
    body: JSON.stringify({
      data: [
        {
          event_name: eventName,
          event_time: Math.floor(Date.now() / 1000),
          event_id: eventId,
          action_source: 'website',
          event_source_url: eventSourceUrl || process.env.APP_BASE_URL,
          user_data: userData,
          custom_data: customData
        }
      ]
    })
  });
}

export async function createCustomAudience({ name, description, subtype = 'CUSTOM', customer_file_source = 'USER_PROVIDED_ONLY' }) {
  return metaFetch(`/${process.env.META_AD_ACCOUNT_ID}/customaudiences`, {
    method: 'POST',
    body: JSON.stringify({ name, description, subtype, customer_file_source })
  });
}

export async function uploadUsersToAudience({ audienceId, payload }) {
  return metaFetch(`/${audienceId}/users`, {
    method: 'POST',
    body: JSON.stringify(payload)
  });
}

export async function createCampaign({ name, objective = 'OUTCOME_SALES', status = 'PAUSED', special_ad_categories = [] }) {
  return metaFetch(`/${process.env.META_AD_ACCOUNT_ID}/campaigns`, {
    method: 'POST',
    body: JSON.stringify({ name, objective, status, special_ad_categories })
  });
}

export async function createAdSet(payload) {
  return metaFetch(`/${process.env.META_AD_ACCOUNT_ID}/adsets`, {
    method: 'POST',
    body: JSON.stringify(payload)
  });
}

export async function createAdCreative(payload) {
  return metaFetch(`/${process.env.META_AD_ACCOUNT_ID}/adcreatives`, {
    method: 'POST',
    body: JSON.stringify(payload)
  });
}

export async function createAd(payload) {
  return metaFetch(`/${process.env.META_AD_ACCOUNT_ID}/ads`, {
