export function segmentUser(user) {
  const tags = new Set(user.tags || []);
  const now = Date.now();
  const last = user.lastActivityAt ? new Date(user.lastActivityAt).getTime() : 0;
  const daysSinceLast = last ? (now - last) / (1000 * 60 * 60 * 24) : 999;

  if (daysSinceLast <= 7) tags.add('hot');
  else if (daysSinceLast <= 30) tags.add('warm');
  else tags.add('cold');

  if (user.packageType === 'honeymoon') tags.add('honeymoon');
  if (user.packageType === 'family') tags.add('family');
  if (user.totalValue >= 1000) tags.add('high_value');
  if (user.leadStatus === 'abandoned') tags.add('abandoned_lead');

  return Array.from(tags);
}

