export function summarizeInsights(data = []) {
  return data.map((row) => ({
    campaign: row.campaign_name,
    adset: row.adset_name,
    spend: Number(row.spend || 0),
    clicks: Number(row.clicks || 0),
    cpc: Number(row.cpc || 0),
    ctr: Number(row.ctr || 0),
    reach: Number(row.reach || 0),
    impressions: Number(row.impressions || 0),
    purchase_roas: Array.isArray(row.purchase_roas) && row.purchase_roas[0] ? Number(row.purchase_roas[0].value || 0) : 0
  }));
}

export function getOptimizerActions(rows, targetCpa, minRoas) {
  return rows.map((row) => {
    const spend = Number(row.spend || 0);
    const clicks = Number(row.clicks || 0);
    const actions = Array.isArray(row.actions) ? row.actions : [];
    const leadAction = actions.find((a) => a.action_type === 'lead');
    const leads = leadAction ? Number(leadAction.value) : 0;
    const cpa = leads > 0 ? spend / leads : spend;
    const roas = Array.isArray(row.purchase_roas) && row.purchase_roas[0] ? Number(row.purchase_roas[0].value || 0) : 0;

    if (leads === 0 && spend > targetCpa * 2) {
      return { adsetId: row.adset_id, action: 'PAUSE', reason: 'No leads and spend too high', cpa, roas, clicks };
    }

    if (cpa > targetCpa && spend > targetCpa) {
      return { adsetId: row.adset_id, action: 'PAUSE', reason: 'CPA above target', cpa, roas, clicks };
    }

    if (roas >= minRoas) {
      return { adsetId: row.adset_id, action: 'SCALE', reason: 'ROAS above target', cpa, roas, clicks };
    }

    return { adsetId: row.adset_id, action: 'KEEP', reason: 'Within thresholds', cpa, roas, clicks };
  });
}

