import { NextResponse } from 'next/server';
import { connectDB } from '../../../../lib/db';
import User from '../../../../models/User';
import Event from '../../../../models/Event';
import { sendConversionsEvent } from '../../../../lib/meta';
import { hashUser } from '../../../../lib/hash';

export async function POST(request) {
  try {
    const body = await request.json();
    await connectDB();

    let user = null;
    if (body.email) {
      user = await User.findOne({ email: body.email });
    }

    if (!user) {
      user = await User.create({
        email: body.email || '',
        phone: body.phone || '',
        firstName: body.firstName || '',
        lastName: body.lastName || '',
        destinationInterest: body.destination || '',
        packageType: body.packageType || '',
        lastActivityAt: new Date()
      });
    } else {
      user.lastActivityAt = new Date();
      if (body.destination) user.destinationInterest = body.destination;
      if (body.packageType) user.packageType = body.packageType;
      await user.save();
    }

    const eventId = `evt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

    const event = await Event.create({
      userId: user._id,
      eventName: body.eventName,
      destination: body.destination || '',
      packageType: body.packageType || '',
      sourceUrl: body.sourceUrl || process.env.APP_BASE_URL,
      metaEventId: eventId,
      value: Number(body.value || 0)
    });

    const hashed = hashUser(user);
    const userData = {};
    if (hashed.email) userData.em = [hashed.email];
    if (hashed.phone) userData.ph = [hashed.phone];
    if (hashed.fn) userData.fn = [hashed.fn];
    if (hashed.ln) userData.ln = [hashed.ln];
    if (hashed.country) userData.country = [hashed.country];

    const capiResponse = await sendConversionsEvent({
      eventName: body.eventName,
      eventId,
      userData,
      customData: {
        currency: process.env.DEFAULT_CURRENCY || 'USD',
        value: Number(body.value || 0),
        content_name: body.destination || 'Travel Package',
        content_category: body.packageType || 'travel'
      },
      eventSourceUrl: body.sourceUrl || process.env.APP_BASE_URL
    });

    return NextResponse.json({ ok: true, eventId, dbEventId: event._id, capiResponse });
  } catch (error) {
    return NextResponse.json({ ok: false, error: error.message }, { status: 500 });
  }
}

