import { NextResponse } from 'next/server';
import { connectDB } from '../../../../lib/db';
import User from '../../../../models/User';
import { segmentUser } from '../../../../services/audienceEngine';
import { createCustomAudience, uploadUsersToAudience } from '../../../../lib/meta';
import { hashUser } from '../../../../lib/hash';

export async function POST(request) {
  try {
    const body = await request.json();
    const segment = body.segment || 'hot';
    const audienceName = body.audienceName || `Travel Audience - ${segment}`;

    await connectDB();
    const users = await User.find({});
    const filtered = users.filter((user) => segmentUser(user).includes(segment));

    const created = await createCustomAudience({
      name: audienceName,
      description: `Segment synced from Next.js bot: ${segment}`
    });

    const payloadUsers = filtered
      .map((user) => hashUser(user))
      .filter((u) => u.email || u.phone)
      .map((u) => [u.email || '', u.phone || '']);

    const uploadRes = await uploadUsersToAudience({
      audienceId: created.id,
      payload: {
        payload: { schema: ['EMAIL', 'PHONE'], data: payloadUsers },
        session: { session_id: Date.now(), batch_seq: 1, last_batch_flag: true, estimated_num_total: payloadUsers.length }
      }
    });

    return NextResponse.json({ ok: true, audienceId: created.id, audienceName, matchedUsers: payloadUsers.length, uploadRes });
  } catch (error) {
    return NextResponse.json({ ok: false, error: error.message }, { status: 500 });
  }
}

