import { NextResponse } from 'next/server';
import { getInsights, updateAdSetStatus } from '../../../../lib/meta';
import { getOptimizerActions } from '../../../../services/reporting';

export async function GET() {
  try {
    const targetCpa = Number(process.env.OPTIMIZER_TARGET_CPA || 6);
    const minRoas = Number(process.env.OPTIMIZER_MIN_ROAS || 2.5);

    const raw = await getInsights({
      level: 'adset',
      fields: 'campaign_name,adset_name,adset_id,spend,clicks,cpc,ctr,reach,impressions,actions,purchase_roas'
    });

    const actions = getOptimizerActions(raw.data || [], targetCpa, minRoas);

    const applied = [];
    for (const action of actions) {
      if (action.action === 'PAUSE') {
        const res = await updateAdSetStatus(action.adsetId, 'PAUSED');
        applied.push({ ...action, api: res });
      } else {
        applied.push(action);
      }
    }

    return NextResponse.json({ ok: true, targetCpa, minRoas, actions: applied });
  } catch (error) {
    return NextResponse.json({ ok: false, error: error.message }, { status: 500 });
  }
}

